class ChiselCircuitAnnotation private (val elaboratedCircuit: ElaboratedCircuit)
    extends NoTargetAnnotation
    with ChiselOption
    with Unserializable
    with Product
    with Serializable {
  def canEqual(that: Any): Boolean = that.isInstanceOf[ChiselCircuitAnnotation]

